#include <bits/stdc++.h>
using namespace std;

static string json_escape(const string& s) {
    string out;
    for (char c : s) {
        if (c == '"' || c == '\\') out += '\\', out += c;
        else if (c == '\n') out += "\\n";
        else out += c;
    }
    return out;
}

static void verdict(const string& status, const string& detail) {
    const char* path = getenv("ALKALIBASE_VERDICT_FILE");
    ofstream out(path ? path : "/tmp/alkalibase-missing-verdict.json");
    out << "{\"status\":\"" << status << "\",\"detail\":\"" << json_escape(detail) << "\"}";
}

int main(int argc, char** argv) {
    if (argc < 3) return 2;
    ifstream input(argv[1]), answer(argv[2]);
    long long l, r, x;
    if (!(input >> l >> r)) return 2;
    if (!(answer >> x)) return 2;
    cout << l << ' ' << r << endl;
    int queries = 0;
    string op;
    while (cin >> op) {
        long long y;
        if (!(cin >> y)) {
            verdict("WA", "missing value");
            return 0;
        }
        if (op == "?") {
            ++queries;
            if (queries > 100) {
                verdict("WA", "too many queries");
                return 0;
            }
            if (x > y) cout << -1 << endl;
            else if (x == y) cout << 0 << endl;
            else cout << 1 << endl;
        } else if (op == "!") {
            verdict(y == x ? "AC" : "WA", y == x ? "ok" : "wrong answer");
            return 0;
        } else {
            verdict("WA", "unknown command");
            return 0;
        }
    }
    verdict("WA", "no final answer");
    return 0;
}
